// Get both the HTML and the original source info
const items = $input.all();
const html = items[0].json.data || '';
// Access the source info from the previous node (Route by Type)
const sourceInfo = $node["Route by Type"].json;

// Make sure we have the baseUrl
const baseUrl = sourceInfo.baseUrl || 'https://www.tagesspiegel.de';
const sourceName = sourceInfo.name || 'Tagesspiegel';
const language = sourceInfo.language || 'de';
const retrievedAt = sourceInfo.retrievedAt || new Date().toISOString().split('T')[0];

// Parse HTML to extract article links
const articlePattern = /<article[^>]*>([\s\S]*?)<\/article>/gi;
const linkPattern = /href="([^"]+)"/gi;

const articles = [];
const uniqueLinks = new Set();

let articleMatch;
while ((articleMatch = articlePattern.exec(html)) !== null) {
  const articleHtml = articleMatch[1];
  let linkMatch;
  while ((linkMatch = linkPattern.exec(articleHtml)) !== null) {
    const href = linkMatch[1];
    // Only process relative links that start with /
    if (href && href.startsWith('/') && !href.startsWith('//') && !uniqueLinks.has(href)) {
      uniqueLinks.add(href);
      articles.push({
        json: {
          url: baseUrl + href,
          source: sourceName,
          language: language,
          retrievedAt: retrievedAt,
          baseUrl: baseUrl
        }
      });
    }
  }
}

// Return first 20 articles
return articles.slice(0, 20);

// Configuration for all news sources
const sources = [
  {
    name: 'Tagesspiegel',
    baseUrl: 'https://www.tagesspiegel.de',
    language: 'de',
    type: 'scraping'
  },
  {
    name: 'Bild',
    rssUrl: 'https://www.bild.de/feed/alles.xml',
    language: 'de',
    type: 'rss_scraping'
  },
  {
    name: 'BBC',
    rssUrl: 'https://feeds.bbci.co.uk/news/world/rss.xml',
    language: 'en',
    type: 'rss'
  }
];

return sources.map(config => ({
  json: {
    ...config,
    retrievedAt: new Date().toISOString().split('T')[0]
  }
}));

const html = $input.item.json.data || '';
const meta = $input.item.json;

// If there's an error, skip this item
if ($input.item.json.error || !html) {
  return {
    json: {
      ...meta,
      skip: true
    }
  };
}

// Check for paywall
if (html.includes('id="paywall"')) {
  return {
    json: {
      ...meta,
      skip: true
    }
  };
}

let title = '';
let content = '';
let publishedAt = null;

// Extract title
const titleMatch = html.match(/<h1[^>]*>([^<]+)<\/h1>/);
if (titleMatch) {
  title = titleMatch[1].trim();
}

// Extract publish date
const timeMatch = html.match(/<time[^>]*datetime="([^"]+)"/);
if (timeMatch) {
  publishedAt = timeMatch[1].split('T')[0];
}

// Extract paragraphs
const paragraphPattern = /<p[^>]*>([^<]+)<\/p>/gi;
const paragraphs = [];
let match;

while ((match = paragraphPattern.exec(html)) !== null) {
  const text = match[1].trim();
  if (text.length > 10) {
    paragraphs.push(text);
  }
}

// Skip first and last 2 paragraphs as in original code
if (paragraphs.length > 3) {
  content = paragraphs.slice(1, -2).join(' ');
} else {
  content = paragraphs.join(' ');
}

const id = `${meta.source}-${publishedAt || meta.retrievedAt}-${Math.floor(Math.random() * 1000)}`;

return {
  json: {
    id: id,
    source: meta.source,
    url: meta.url,
    title: title,
    body: content,
    language: meta.language,
    published_at: publishedAt,
    retrieved_at: meta.retrievedAt,
    skip: false
  }
};

const items = $input.all();
const xml = items[0].json.data || '';
// Get source info from the Route node
const sourceInfo = $node["Route by Type"].json;

const itemPattern = /<item>([\s\S]*?)<\/item>/gi;
const titlePattern = /<title><!\[CDATA\[([^\]]+)\]\]><\/title>|<title>([^<]+)<\/title>/;
const linkPattern = /<link>([^<]+)<\/link>/;
const pubDatePattern = /<pubDate>([^<]+)<\/pubDate>/;

const articles = [];
let match;
let counter = 0;

while ((match = itemPattern.exec(xml)) !== null && counter < 10) {
  const itemXml = match[1];

  const titleMatch = itemXml.match(titlePattern);
  const linkMatch = itemXml.match(linkPattern);
  const pubDateMatch = itemXml.match(pubDatePattern);

  if (titleMatch && linkMatch) {
    const title = titleMatch[1] || titleMatch[2];
    const url = linkMatch[1].trim();
    let publishedAt = null;

    if (pubDateMatch) {
      try {
        publishedAt = new Date(pubDateMatch[1]).toISOString().split('T')[0];
      } catch (e) {
        publishedAt = sourceInfo.retrievedAt;
      }
    }

    if (url) { // Only add if URL exists
      articles.push({
        json: {
          url: url,
          title: title,
          source: sourceInfo.name,
          language: sourceInfo.language,
          published_at: publishedAt,
          retrieved_at: sourceInfo.retrievedAt
        }
      });
      counter++;
    }
  }
}

return articles;

const html = $input.item.json.data || '';
const meta = $input.item.json;

// If there's an error, skip this item
if ($input.item.json.error || !html) {
  return {
    json: {
      ...meta,
      skip: true
    }
  };
}

let content = '';

// Try to find article body in common containers
const bodySelectors = [
  /<article[^>]*>([\s\S]*?)<\/article>/,
  /<div[^>]*class="[^"]*article-body[^"]*"[^>]*>([\s\S]*?)<\/div>/,
  /<div[^>]*class="[^"]*content[^"]*"[^>]*>([\s\S]*?)<\/div>/,
  /<main[^>]*>([\s\S]*?)<\/main>/
];

let bodyHtml = '';
for (const selector of bodySelectors) {
  const match = html.match(selector);
  if (match) {
    bodyHtml = match[1];
    break;
  }
}

if (!bodyHtml) {
  bodyHtml = html;
}

// Extract all paragraphs
const paragraphPattern = /<p[^>]*>([^<]+)<\/p>/gi;
const paragraphs = [];
let match;

while ((match = paragraphPattern.exec(bodyHtml)) !== null) {
  const text = match[1].trim()
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");

  if (text.length > 20) {
    paragraphs.push(text);
  }
}

content = paragraphs.join(' ');

// Update title if we can find a better one
let title = meta.title;
const h1Match = html.match(/<h1[^>]*>([^<]+)<\/h1>/);
if (h1Match) {
  title = h1Match[1].trim();
}

const id = `${meta.source}-${meta.published_at || meta.retrieved_at}-${Math.floor(Math.random() * 1000)}`;

return {
  json: {
    id: id,
    source: meta.source,
    url: meta.url,
    title: title,
    body: content,
    language: meta.language,
    published_at: meta.published_at,
    retrieved_at: meta.retrieved_at
  }
};

const items = $input.all();
const xml = items[0].json.data || '';
// Get source info from the Route node
const sourceInfo = $node["Route by Type"].json;

const itemPattern = /<item>([\s\S]*?)<\/item>/gi;
const linkPattern = /<link>([^<]+)<\/link>/;

const articles = [];
let match;
let counter = 0;

while ((match = itemPattern.exec(xml)) !== null && counter < 15) {
  const itemXml = match[1];
  const linkMatch = itemXml.match(linkPattern);

  if (linkMatch) {
    const url = linkMatch[1].trim();

    if (url) { // Only add if URL exists
      articles.push({
        json: {
          url: url,
          source: sourceInfo.name,
          language: sourceInfo.language,
          retrievedAt: sourceInfo.retrievedAt
        }
      });
      counter++;
    }
  }
}

return articles;

const html = $input.item.json.data || '';
const meta = $input.item.json;

// If there's an error, skip this item
if ($input.item.json.error || !html) {
  return {
    json: {
      ...meta,
      skip: true
    }
  };
}

// Check for Bild paywall
if (html.includes('class="offer-module"')) {
  return {
    json: {
      ...meta,
      skip: true
    }
  };
}

let title = '';
let content = '';
let publishedAt = null;

// Extract title from Bild-specific selector
const titleMatch = html.match(/<span[^>]*class="[^"]*headline[^"]*"[^>]*>([^<]+)<\/span>/);
if (titleMatch) {
  title = titleMatch[1].trim();
}

// Extract publish date
const timeMatch = html.match(/<time[^>]*datetime="([^"]+)"/);
if (timeMatch) {
  publishedAt = timeMatch[1].split('T')[0];
}

// Extract paragraphs from article body
const articleBodyMatch = html.match(/<div[^>]*class="[^"]*article-body[^"]*"[^>]*>([\s\S]*?)<\/div>/);
if (articleBodyMatch) {
  const bodyHtml = articleBodyMatch[1];
  const paragraphPattern = /<p[^>]*>([^<]+)<\/p>/gi;
  const paragraphs = [];
  let match;

  while ((match = paragraphPattern.exec(bodyHtml)) !== null) {
    const text = match[1].trim();
    if (text.length > 10) {
      paragraphs.push(text);
    }
  }

  content = paragraphs.join(' ');
}

// Skip if content is too short (less than 1000 chars)
if (content.length <= 1000) {
  return {
    json: {
      ...meta,
      skip: true
    }
  };
}

const id = `${meta.source}-${publishedAt || meta.retrievedAt}-${Math.floor(Math.random() * 1000)}`;

return {
  json: {
    id: id,
    source: meta.source,
    url: meta.url,
    title: title,
    body: content,
    language: meta.language,
    published_at: publishedAt,
    retrieved_at: meta.retrievedAt,
    skip: false
  }
};

const articles = $input.all().map(item => item.json);

// Clean articles - remove skip field and ensure all required fields
const cleanedArticles = articles
  .filter(article => article.url && article.source) // Extra safety check
  .map(article => ({
    id: article.id,
    source: article.source,
    url: article.url,
    title: article.title || '',
    body: article.body || '',
    language: article.language,
    published_at: article.published_at || null,
    retrieved_at: article.retrieved_at
  }));

// Return both JSON string and array
return [{
  json: {
    fileContent: JSON.stringify(cleanedArticles, null, 2),
    articles: cleanedArticles,
    count: cleanedArticles.length,
    timestamp: new Date().toISOString()
  }
}];
